/* ============================ API client ============================ */
const API_BASE = (typeof window !== "undefined" && window.__ECG_API_URL__) || "";
let TOKEN = null;
async function api(path, method = "GET", body) {
  const res = await fetch(API_BASE + path, {
    method,
    headers: { "Content-Type": "application/json", ...(TOKEN ? { Authorization: `Bearer ${TOKEN}` } : {}) },
    body: body ? JSON.stringify(body) : undefined,
  });
  if (res.status === 401) { try { localStorage.removeItem("ecg_token"); localStorage.removeItem("ecg_user"); sessionStorage.removeItem("ecg_token"); sessionStorage.removeItem("ecg_user"); } catch {} }
  if (!res.ok) { const j = await res.json().catch(() => ({})); throw new Error(j.error || res.statusText); }
  return res.status === 204 ? null : res.json();
}
const stripId = ({ id, ...rest }) => rest;
const createRecord = (module, collection, facilityId, data) => api("/api/records", "POST", { module, collection, facilityId, data }).then((r) => r.id);
const updateRecord = (id, data) => api(`/api/records/${id}`, "PATCH", { data });
const deleteRecord = (id) => api(`/api/records/${id}`, "DELETE");
const onErr = () => alert("Couldn’t reach the server — that change may not have saved. Check your connection.");

// Build the in-memory data shape from flat records. Every row keeps its record id.
function recordsToData(records) {
  const data = { rentals: {}, modules: {}, budget: {} };
  records.forEach((r) => {
    if (r.module === "census") return; // bedboard is managed by bedboardStore
    const row = { id: r.id, ...r.data };
    if (r.module === "rentals") (data.rentals[r.facility_id] ||= []).push(row);
    else if (r.module === "budget") (data.budget[r.facility_id] ||= []).push(row);
    else { (data.modules[r.module] ||= {}); (data.modules[r.module][r.facility_id] ||= {}); (data.modules[r.module][r.facility_id][r.collection] ||= []).push(row); }
  });
  return data;
}
