function ensurePath(d, mk, fid, tabId) {
  d.modules ||= {}; d.modules[mk] ||= {}; d.modules[mk][fid] ||= {}; d.modules[mk][fid][tabId] ||= [];
  return d.modules[mk][fid][tabId];
}
const moduleRows = (data, mk, fid) => { const o = {}; (TRACKERS[mk].tabs).forEach((t) => (o[t.id] = data.modules?.[mk]?.[fid]?.[t.id] || [])); return o; };
const allModuleRows = (data, mk) => { const o = {}; TRACKERS[mk].tabs.forEach((t) => (o[t.id] = FACILITIES.flatMap((f) => data.modules?.[mk]?.[f.id]?.[t.id] || []))); return o; };

function TrackerModule({ facility, moduleKey, data, update }) {
  const cfg = TRACKERS[moduleKey];
  const [tabId, setTabId] = useState(cfg.tabs[0].id);
  const [modal, setModal] = useState(null);
  const [importing, setImporting] = useState(false);
  const [q, setQ] = useState("");
  // If the selected tab isn't part of this module (e.g. after switching
  // modules), fall back to the first tab instead of crashing.
  useEffect(() => { if (!cfg.tabs.some((t) => t.id === tabId)) setTabId(cfg.tabs[0].id); }, [moduleKey]);
  const tab = cfg.tabs.find((t) => t.id === tabId) || cfg.tabs[0];
  const rowsByTab = moduleRows(data, moduleKey, facility.id);
  const rows = rowsByTab[tab.id] || [];
  const visible = tab.cols.filter((c) => !c.hideCol);

  const save = async (row) => {
    try {
      if (row.id && rows.some((x) => x.id === row.id)) { await updateRecord(row.id, stripId(row)); update((d) => { const a = ensurePath(d, moduleKey, facility.id, tabId); const i = a.findIndex((x) => x.id === row.id); if (i >= 0) a[i] = row; }); }
      else { const id = await createRecord(moduleKey, tabId, facility.id, stripId(row)); update((d) => { ensurePath(d, moduleKey, facility.id, tabId).push({ ...row, id }); }); }
    } catch { onErr(); }
  };
  const del = async (id) => { try { await deleteRecord(id); update((d) => { const a = ensurePath(d, moduleKey, facility.id, tabId); const i = a.findIndex((x) => x.id === id); if (i >= 0) a.splice(i, 1); }); } catch { onErr(); } };
  const importRows = async (mapped) => {
    try {
      const created = [];
      for (const r of mapped) { const id = await createRecord(moduleKey, tabId, facility.id, r); created.push({ ...r, id }); }
      update((d) => { const a = ensurePath(d, moduleKey, facility.id, tabId); created.forEach((x) => a.push(x)); });
    } catch { onErr(); }
  };

  const display = rows.filter((r) => !q || Object.values(r).some((v) => String(v ?? "").toLowerCase().includes(q.toLowerCase())));

  return (
    <div>
      <SectionHead title={cfg.label} right={<div className="flex items-center gap-2"><ImportBtn onClick={() => setImporting(true)} /><AddBtn onClick={() => setModal({})}>Add</AddBtn></div>} stats={cfg.kpis(rowsByTab)} />
      {cfg.tabs.length > 1 && (
        <div className="flex flex-wrap gap-1 mb-3">{cfg.tabs.map((t) => (
          <button key={t.id} onClick={() => setTabId(t.id)} className="px-3 py-1.5 rounded-full text-sm" style={tabId === t.id ? { background: BRAND.ink, color: "#fff" } : { background: BRAND.card, color: BRAND.inkSoft, border: `1px solid ${BRAND.line}` }}>{t.label}</button>
        ))}</div>
      )}
      <div className="relative max-w-xs mb-3"><Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2" style={{ color: "#b3ada1" }} />
        <input style={{ ...inpStyle, paddingLeft: 34 }} placeholder="Search…" value={q} onChange={(e) => setQ(e.target.value)} /></div>
      {display.length === 0 ? <Empty text="Nothing logged here yet — add the first entry, or import a CSV." /> : (
        <Table head={[...visible.map((c) => c.label), ""]}>
          {display.map((row) => (
            <tr key={row.id} className="group" style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
              {visible.map((c) => <Td key={c.k} right={c.type === "money" || c.type === "num" || c.money} soft={c.soft}>{renderCell(c, row)}</Td>)}
              <Td><RowActions onEdit={() => setModal(row)} onDelete={() => del(row.id)} /></Td>
            </tr>
          ))}
        </Table>
      )}
      {modal && <TrackerForm tab={tab} label={cfg.label} row={modal} onClose={() => setModal(null)} onSave={(r) => { save(r); setModal(null); }} />}
      {importing && <ImportModal tab={tab} label={cfg.label} onClose={() => setImporting(false)} onImport={(mapped) => { importRows(mapped); setImporting(false); }} />}
    </div>
  );
}

function renderCell(c, row) {
  let v = c.type === "computed" ? c.compute(row) : row[c.k];
  if (v == null || v === "") return <span style={{ color: "#c4beb2" }}>—</span>;
  if (c.pill) return <Pill tone={c.pill(v)}>{v}</Pill>;
  if (c.type === "money" || c.money) return money(num(v));
  if (c.type === "date") return fmtDate(v);
  return v;
}

/* ---- CSV import (shared) ---- */
function parseCSV(text) {
  const t = text.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  const rows = []; let row = [], field = "", inQ = false, i = 0;
  while (i < t.length) {
    const c = t[i];
    if (inQ) {
      if (c === '"') { if (t[i + 1] === '"') { field += '"'; i += 2; continue; } inQ = false; i++; continue; }
      field += c; i++; continue;
    }
    if (c === '"') { inQ = true; i++; continue; }
    if (c === ",") { row.push(field); field = ""; i++; continue; }
    if (c === "\n") { row.push(field); rows.push(row); row = []; field = ""; i++; continue; }
    field += c; i++;
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows.filter((r) => r.some((x) => String(x).trim() !== ""));
}
const guessHeader = (headers, col) => {
  const want = [col.label.toLowerCase(), col.k.toLowerCase()];
  let best = "";
  headers.forEach((h) => { const hl = h.toLowerCase().trim(); if (want.some((w) => hl === w || hl.includes(w) || w.includes(hl))) best = best || h; });
  return best;
};

function ImportModal({ tab, label, onClose, onImport }) {
  const editable = tab.cols.filter((c) => c.type !== "computed");
  const [headers, setHeaders] = useState(null);
  const [dataRows, setDataRows] = useState([]);
  const [map, setMap] = useState({});
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);

  const onFile = (e) => {
    const file = e.target.files?.[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const rows = parseCSV(String(reader.result));
        if (rows.length < 2) { setErr("That file has no data rows."); return; }
        const hs = rows[0].map((h) => h.trim());
        setHeaders(hs); setDataRows(rows.slice(1));
        const auto = {}; editable.forEach((c) => { auto[c.k] = guessHeader(hs, c); }); setMap(auto); setErr("");
      } catch { setErr("Couldn’t read that file. Make sure it’s a .csv export."); }
    };
    reader.readAsText(file);
  };
  const mappedRow = (r) => { const o = {}; editable.forEach((c) => { const h = map[c.k]; if (h) { const idx = headers.indexOf(h); o[c.k] = idx >= 0 ? (r[idx] ?? "").trim() : ""; } }); return o; };
  const preview = dataRows.slice(0, 5).map(mappedRow);
  const ready = headers && Object.values(map).some(Boolean) && !busy;

  return (
    <Modal title={`Import into ${label}`} onClose={onClose} wide>
      {!headers ? (
        <div>
          <p className="text-sm mb-3" style={{ color: BRAND.inkSoft }}>Upload a <b>.csv</b> export (from PointClickCare, OnCare, Excel — "Save As → CSV"). You’ll match its columns to the fields here before anything is imported.</p>
          <label className="block rounded-xl border-2 border-dashed p-8 text-center cursor-pointer" style={{ borderColor: BRAND.line }}>
            <Upload size={22} style={{ color: BRAND.tanDeep }} className="mx-auto mb-2" />
            <span className="text-sm" style={{ color: BRAND.ink }}>Choose CSV file</span>
            <input type="file" accept=".csv,text/csv" onChange={onFile} className="hidden" />
          </label>
          {err && <div className="text-xs mt-3" style={{ color: TONE.bad.fg }}>{err}</div>}
        </div>
      ) : (
        <div>
          <p className="text-sm mb-3" style={{ color: BRAND.inkSoft }}>Match each field to a column from your file. Leave as “—” to skip. {dataRows.length} rows found.</p>
          <div className="grid sm:grid-cols-2 gap-2 mb-4">
            {editable.map((c) => (
              <label key={c.k} className="flex items-center justify-between gap-2 text-sm">
                <span style={{ color: BRAND.inkSoft }}>{c.label}</span>
                <select value={map[c.k] || ""} onChange={(e) => setMap((m) => ({ ...m, [c.k]: e.target.value }))} style={{ ...inpStyle, width: "55%" }}>
                  <option value="">—</option>
                  {headers.map((h) => <option key={h} value={h}>{h}</option>)}
                </select>
              </label>
            ))}
          </div>
          <div className="text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Preview (first {preview.length})</div>
          <div className="rounded-lg overflow-x-auto mb-4" style={{ border: `1px solid ${BRAND.line}` }}>
            <table className="w-full text-xs"><thead><tr style={{ background: BRAND.lineSoft }}>{editable.filter((c) => map[c.k]).map((c) => <th key={c.k} className="px-2 py-1 text-left font-medium" style={{ color: BRAND.inkSoft }}>{c.label}</th>)}</tr></thead>
              <tbody>{preview.map((r, i) => <tr key={i} style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>{editable.filter((c) => map[c.k]).map((c) => <td key={c.k} className="px-2 py-1">{r[c.k] || "—"}</td>)}</tr>)}</tbody></table>
          </div>
          <div className="flex justify-between items-center">
            <button onClick={() => { setHeaders(null); setDataRows([]); }} className="text-sm" style={{ color: BRAND.inkSoft }}>← Choose a different file</button>
            <button disabled={!ready} onClick={() => { setBusy(true); onImport(dataRows.map(mappedRow)); }} className="inline-flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm text-white" style={{ background: ready ? BRAND.ink : "#bdb7ab" }}>
              <Upload size={15} /> {busy ? "Importing…" : `Import ${dataRows.length} rows`}
            </button>
          </div>
        </div>
      )}
    </Modal>
  );
}
const ImportBtn = ({ onClick }) => <button onClick={onClick} className="inline-flex items-center gap-1.5 rounded-lg px-3 py-2 text-sm shrink-0" style={{ border: `1px solid ${BRAND.line}`, color: BRAND.ink, background: BRAND.card }}><Upload size={15} /> Import</button>;


function TrackerForm({ tab, label, row, onClose, onSave }) {
  const [f, setF] = useState({ id: row.id, ...Object.fromEntries(tab.cols.filter((c) => c.type !== "computed").map((c) => [c.k, row[c.k] ?? ""])) });
  const set = (k, v) => setF((p) => ({ ...p, [k]: v }));
  const editable = tab.cols.filter((c) => c.type !== "computed");
  const first = editable[0];
  const ok = first ? String(f[first.k] || "").trim().length > 0 : true;
  return (
    <Modal title={row.id ? "Edit entry" : "Add to " + label} onClose={onClose} wide>
      <div className="grid sm:grid-cols-2 gap-x-3">
        {editable.map((c) => (
          <div key={c.k} className={c.type === "long" ? "sm:col-span-2" : ""}>
            <Field label={c.label}>
              {c.type === "select" ? <Sel v={f[c.k]} on={(v) => set(c.k, v)} options={["", ...c.options]} />
                : c.type === "long" ? <textarea rows={2} style={inpStyle} value={f[c.k]} onChange={(e) => set(c.k, e.target.value)} />
                : <In type={c.type === "date" ? "date" : "text"} v={f[c.k]} on={(v) => set(c.k, v)} autoFocus={c === first} />}
            </Field>
          </div>
        ))}
      </div>
      <SaveRow ok={ok} onClose={onClose} onSave={() => onSave(f)} />
    </Modal>
  );
}

const stars5 = (n) => "★".repeat(Number(n) || 0) + "☆".repeat(5 - (Number(n) || 0));
const PROFILE_FIELDS = [
  { k: "beds", label: "Bed Capacity" }, { k: "address", label: "Address" },
  { k: "rdo", label: "Regional Ops (RDO)" }, { k: "rdcs", label: "Regional Clinical (RDCS)" },
  { k: "survey", label: "Survey Status" }, { k: "surveyNotes", label: "Survey Notes", long: true },
  { k: "ratingOverall", label: "Overall Rating", rating: true }, { k: "ratingHealth", label: "Health Survey", rating: true },
  { k: "ratingQuality", label: "Quality Measures", rating: true }, { k: "ratingStaffing", label: "Staffing", rating: true },
];
const isVacant = (name) => /vacant|open|^—|^-$/i.test((name || "").trim()) || !(name || "").trim();

function RosterModule({ facility, data, update }) {
  const bucket = (data.modules && data.modules.roster && data.modules.roster[facility.id]) || {};
  const staff = bucket.staff || [];
  const profile = (bucket.profile && bucket.profile[0]) || {};
  const [modal, setModal] = useState(null);
  const [editP, setEditP] = useState(false);

  const ensure = (d) => { (d.modules ||= {}); (d.modules.roster ||= {}); (d.modules.roster[facility.id] ||= {}); const b = d.modules.roster[facility.id]; (b.staff ||= []); (b.profile ||= []); return b; };
  const setProfile = (fn) => update((d) => { const b = ensure(d); if (!b.profile[0]) b.profile[0] = {}; fn(b.profile[0]); });

  // debounce create-or-update the single profile record
  const snap = JSON.stringify(stripId(profile));
  const lastRef = useRef(null);
  useEffect(() => {
    if (lastRef.current === null) { lastRef.current = snap; return; }
    if (lastRef.current === snap) return;
    lastRef.current = snap;
    const t = setTimeout(async () => {
      try {
        if (profile.id) await updateRecord(profile.id, JSON.parse(snap));
        else { const id = await createRecord("roster", "profile", facility.id, JSON.parse(snap)); update((d) => { const b = ensure(d); if (!b.profile[0]) b.profile[0] = {}; b.profile[0].id = id; }); }
      } catch {}
    }, 700);
    return () => clearTimeout(t);
  }, [snap]);

  const saveStaff = async (row) => {
    try {
      if (row.id && staff.some((x) => x.id === row.id)) { await updateRecord(row.id, stripId(row)); update((d) => { const b = ensure(d); const i = b.staff.findIndex((x) => x.id === row.id); if (i >= 0) b.staff[i] = row; }); }
      else { const id = await createRecord("roster", "staff", facility.id, stripId(row)); update((d) => { ensure(d).staff.push({ ...row, id }); }); }
    } catch { onErr(); }
  };
  const delStaff = async (id) => { try { await deleteRecord(id); update((d) => { const b = ensure(d); b.staff = b.staff.filter((x) => x.id !== id); }); } catch { onErr(); } };

  const headcount = staff.reduce((a, s) => a + (parseInt(s.staff) || 0), 0);
  const vacancies = staff.filter((s) => isVacant(s.name)).length;

  return (
    <div>
      <SectionHead title="Roster" right={<AddBtn onClick={() => setModal({})}>Add role</AddBtn>}
        stats={[["Roles listed", staff.length], ["Counted staff", headcount], ["Vacancies", vacancies, vacancies ? "warn" : "ok"]]} />

      <div className="rounded-xl p-5 mb-4" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        <div className="flex items-center justify-between mb-3">
          <div className="font-semibold" style={{ fontFamily: SERIF, fontSize: 16 }}>Facility profile</div>
          <button onClick={() => setEditP(!editP)} className="inline-flex items-center gap-1.5 text-xs px-2.5 py-1 rounded-lg" style={editP ? { background: BRAND.ink, color: "#fff" } : { color: BRAND.inkSoft, background: BRAND.lineSoft }}>
            {editP ? <><CheckCircle2 size={13} /> Done</> : <><Pencil size={12} /> Edit</>}
          </button>
        </div>
        {editP ? (
          <div className="grid sm:grid-cols-2 gap-3">
            {PROFILE_FIELDS.map((f) => (
              <label key={f.k} className={f.long ? "sm:col-span-2" : ""}>
                <span className="block text-xs mb-1" style={{ color: BRAND.inkSoft }}>{f.label}</span>
                {f.long ? <textarea rows={4} style={inpStyle} value={profile[f.k] || ""} onChange={(e) => setProfile((p) => { p[f.k] = e.target.value; })} />
                  : f.rating ? <Sel v={String(profile[f.k] ?? "")} on={(v) => setProfile((p) => { p[f.k] = v === "" ? null : Number(v); })} options={["", "1", "2", "3", "4", "5"]} />
                  : <input style={inpStyle} value={profile[f.k] || ""} onChange={(e) => setProfile((p) => { p[f.k] = e.target.value; })} />}
              </label>
            ))}
          </div>
        ) : Object.keys(profile).filter((k) => k !== "id").length === 0 ? <div className="text-sm" style={{ color: "#b0aa9e" }}>No profile yet — tap Edit to add.</div> : (
          <div className="grid sm:grid-cols-2 gap-x-6 gap-y-3">
            {PROFILE_FIELDS.map((f) => {
              const v = profile[f.k]; if (v == null || v === "") return null;
              const tone = f.k === "ratingOverall" ? (v >= 4 ? TONE.ok.fg : v === 3 ? TONE.warn.fg : TONE.bad.fg) : BRAND.ink;
              return (
                <div key={f.k} className={f.long ? "sm:col-span-2" : ""}>
                  <div className="text-[10px] uppercase tracking-wider mb-0.5" style={{ color: BRAND.inkSoft }}>{f.label}</div>
                  <div className="text-sm" style={{ color: tone, whiteSpace: f.long ? "pre-wrap" : "normal" }}>{f.rating ? stars5(v) : v}</div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {staff.length === 0 ? <Empty text="No roster rows yet — add the first role." /> : (
        <Table head={["Department / Role", "Name", "Email", "Phone", "# Staff", "Notes", ""]}>
          {staff.map((s) => (
            <tr key={s.id} className="group" style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
              <Td><span className="font-medium">{s.role}</span></Td>
              <Td>{isVacant(s.name) ? <Pill tone={TONE.warn}>{(s.name || "").trim() || "Open"}</Pill> : s.name}</Td>
              <Td soft>{s.email || "—"}</Td><Td soft>{s.phone || "—"}</Td>
              <Td right>{s.staff || "—"}</Td><Td soft>{s.notes || ""}</Td>
              <Td><RowActions onEdit={() => setModal(s)} onDelete={() => delStaff(s.id)} /></Td>
            </tr>
          ))}
        </Table>
      )}
      {modal && <RosterStaffModal row={modal} onClose={() => setModal(null)} onSave={(r) => { saveStaff(r); setModal(null); }} />}
    </div>
  );
}

function RosterStaffModal({ row, onClose, onSave }) {
  const [f, setF] = useState({ id: row.id, role: row.role || "", name: row.name || "", email: row.email || "", phone: row.phone || "", staff: row.staff || "", notes: row.notes || "" });
  const set = (k, v) => setF((p) => ({ ...p, [k]: v }));
  return (
    <Modal title={row.id ? "Edit role" : "Add role"} onClose={onClose} wide>
      <Grid2><Field label="Department / Role"><In v={f.role} on={(v) => set("role", v)} autoFocus /></Field><Field label="Name"><In v={f.name} on={(v) => set("name", v)} /></Field></Grid2>
      <Grid2><Field label="Email"><In v={f.email} on={(v) => set("email", v)} /></Field><Field label="Phone"><In v={f.phone} on={(v) => set("phone", v)} /></Field></Grid2>
      <Grid2><Field label="# Staff"><In v={f.staff} on={(v) => set("staff", v)} /></Field><div /></Grid2>
      <Field label="Notes"><In v={f.notes} on={(v) => set("notes", v)} /></Field>
      <SaveRow ok={!!f.role.trim()} onClose={onClose} onSave={() => onSave(f)} />
    </Modal>
  );
}

/* In-app toast — replaces browser alert(), which sandboxed previews block */
const toastStore = {
  msg: null, listeners: new Set(), _t: null,
  show(m) { this.msg = m; clearTimeout(this._t); this._t = setTimeout(() => { this.msg = null; this.listeners.forEach((l) => l()); }, 7000); this.listeners.forEach((l) => l()); },
  subscribe(l) { this.listeners.add(l); return () => this.listeners.delete(l); },
};
const toast = (m) => { toastStore.show(m); try { if (typeof window !== "undefined" && !window.__ECG_PREVIEW_NO_ALERT) { /* toast only */ } } catch {} };
function ToastHost() {
  const [, tick] = useState(0);
  useEffect(() => toastStore.subscribe(() => tick((t) => t + 1)), []);
  if (!toastStore.msg) return null;
  return (
    <div style={{ position: "fixed", bottom: 20, left: "50%", transform: "translateX(-50%)", zIndex: 90, maxWidth: 480 }}
      className="rounded-xl px-4 py-3 text-sm shadow-lg" role="status"
      onClick={() => { toastStore.msg = null; toastStore.listeners.forEach((l) => l()); }}>
      <div style={{ background: BRAND.ink, color: "#fff", borderRadius: 12, padding: "10px 14px", cursor: "pointer" }}>{toastStore.msg}</div>
    </div>
  );
}

