const Empty = ({ text }) => <div className="text-center rounded-xl py-12 px-6" style={{ background: BRAND.card, border: `1px dashed ${BRAND.line}` }}><div className="flex justify-center mb-2"><Crown size={24} /></div><div className="text-sm" style={{ color: BRAND.inkSoft }}>{text}</div></div>;

