const Pill = ({ tone, children }) => <span className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-0.5 text-xs font-medium whitespace-nowrap" style={{ background: tone.bg, color: tone.fg }}><span className="h-1.5 w-1.5 rounded-full" style={{ background: tone.dot }} />{children}</span>;
